remedy:
# In child script, before ShowDialog:
Set-StrictMode -Off
$form.ShowDialog() | Out-Null
Set-StrictMode -Version Latest

# In parent event handlers, guard $script: access:
$forceClose = try { $script:_ForceClose } catch { $false }
$timer = try { $script:_ServiceTimer } catch { $null }
if ($null -eq $timer) { return }
